/**
 * @file Component.js
 * @description Marks a class as a component to be managed by the DI container.
 */
class Component {
  /**
   * @param {Array} args - Optional arguments, e.g. a name or configuration
   */
  constructor(args = []) {
    this.args = args;
  }
  
  /**
   * The target type of this annotation (class level)
   */
  static target = 'class';
  
  /**
   * The name of the annotation
   */
  static name = 'Component';
}

module.exports = Component;
